import{_ as t,o as d,c as o,ag as a}from"./chunks/framework.DXGyWiRo.js";const b=JSON.parse('{"title":"Ownership Map","description":"","frontmatter":{},"headers":[],"relativePath":"development/ownership.md","filePath":"development/ownership.md","lastUpdated":1775719799000}'),c={name:"development/ownership.md"};function r(n,e,s,l,i,h){return d(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="ownership-map" tabindex="-1">Ownership Map <a class="header-anchor" href="#ownership-map" aria-label="Permalink to &quot;Ownership Map&quot;">​</a></h1><p><strong>Last updated:</strong> 2026-03-22 <strong>Source of truth:</strong> <a href="https://github.com/rustchatio/rustchat/blob/main/.github/CODEOWNERS" target="_blank" rel="noreferrer"><code>.github/CODEOWNERS</code></a></p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Ownership determines who must review a PR before it can be merged. GitHub enforces this automatically when branch protection is enabled.</p><p>All paths not listed below are owned by <code>@senolcolak</code> (catchall).</p><hr><h2 id="_1-area-map" tabindex="-1">1. Area Map <a class="header-anchor" href="#_1-area-map" aria-label="Permalink to &quot;1. Area Map&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th>Human owner(s)</th><th>Agent authorized</th><th>Risk tier</th></tr></thead><tbody><tr><td><code>backend/src/</code> (non-protected)</td><td><code>@senolcolak</code></td><td><code>backend-agent</code></td><td>standard</td></tr><tr><td><code>backend/src/auth/**</code></td><td><code>@senolcolak</code></td><td><code>backend-agent</code> ⚠️ explicit approval</td><td>elevated</td></tr><tr><td><code>backend/src/api/v4/**</code></td><td><code>@senolcolak</code> + <code>@zoorpha</code></td><td><code>backend-agent</code> ⚠️ co-approval</td><td>elevated</td></tr><tr><td><code>backend/src/mattermost_compat/**</code></td><td><code>@senolcolak</code> + <code>@zoorpha</code></td><td><code>backend-agent</code> ⚠️ co-approval</td><td>elevated</td></tr><tr><td><code>backend/src/a2a/**</code></td><td><code>@senolcolak</code></td><td><code>backend-agent</code> ⚠️ senior review</td><td>elevated</td></tr><tr><td><code>backend/src/realtime/**</code></td><td><code>@senolcolak</code></td><td><code>backend-agent</code></td><td>elevated</td></tr><tr><td><code>backend/migrations/**</code></td><td><code>@senolcolak</code></td><td><code>backend-agent</code></td><td>elevated</td></tr><tr><td><code>backend/tests/**</code></td><td><code>@senolcolak</code></td><td><code>backend-agent</code></td><td>standard</td></tr><tr><td><code>backend/compat/**</code></td><td><code>@senolcolak</code> + <code>@zoorpha</code></td><td><code>compat-agent</code> (read)</td><td>elevated</td></tr><tr><td><code>push-proxy/**</code></td><td><code>@senolcolak</code></td><td><code>backend-agent</code></td><td>standard</td></tr><tr><td><code>frontend/**</code></td><td><code>@senolcolak</code></td><td><code>frontend-agent</code></td><td>standard</td></tr><tr><td><code>tools/mm-compat/**</code></td><td><code>@senolcolak</code> + <code>@zoorpha</code></td><td><code>compat-agent</code> (read)</td><td>elevated</td></tr><tr><td><code>.github/**</code></td><td><code>@senolcolak</code></td><td>none</td><td>standard</td></tr><tr><td><code>.github/CODEOWNERS</code></td><td><code>@senolcolak</code> + <code>@zoorpha</code></td><td>none</td><td>elevated</td></tr><tr><td><code>.governance/**</code></td><td><code>@senolcolak</code> + <code>@zoorpha</code></td><td>none</td><td>architectural</td></tr><tr><td><code>docker/**</code></td><td><code>@senolcolak</code></td><td>none</td><td>standard</td></tr><tr><td><code>scripts/**</code></td><td><code>@senolcolak</code></td><td>none</td><td>standard</td></tr><tr><td><code>docs/**</code></td><td><code>@senolcolak</code></td><td><code>compat-agent</code> (specs/plans only)</td><td>standard</td></tr><tr><td><code>AGENTS.md</code></td><td><code>@senolcolak</code></td><td>none</td><td>standard</td></tr><tr><td><code>*</code> (everything else)</td><td><code>@senolcolak</code></td><td>—</td><td>standard</td></tr></tbody></table><hr><h2 id="_2-dual-owner-areas" tabindex="-1">2. Dual-Owner Areas <a class="header-anchor" href="#_2-dual-owner-areas" aria-label="Permalink to &quot;2. Dual-Owner Areas&quot;">​</a></h2><p>The following areas require <strong>both</strong> owners to approve:</p><table tabindex="0"><thead><tr><th>Area</th><th>Owners</th><th>Why</th></tr></thead><tbody><tr><td><code>backend/compat/**</code></td><td><code>@senolcolak</code> + <code>@zoorpha</code></td><td>Compat contracts must have compat-reviewer sign-off</td></tr><tr><td><code>backend/src/api/v4/**</code></td><td><code>@senolcolak</code> + <code>@zoorpha</code></td><td>Mattermost HTTP compat surface</td></tr><tr><td><code>backend/src/mattermost_compat/**</code></td><td><code>@senolcolak</code> + <code>@zoorpha</code></td><td>Compat utilities</td></tr><tr><td><code>tools/mm-compat/**</code></td><td><code>@senolcolak</code> + <code>@zoorpha</code></td><td>Compat analysis tooling</td></tr><tr><td><code>.github/CODEOWNERS</code></td><td><code>@senolcolak</code> + <code>@zoorpha</code></td><td>Ownership changes affect review routing</td></tr><tr><td><code>.governance/**</code></td><td><code>@senolcolak</code> + <code>@zoorpha</code></td><td>Architectural tier — 2 reviewers required</td></tr></tbody></table><hr><h2 id="_3-risk-tier-auto-elevation" tabindex="-1">3. Risk Tier Auto-Elevation <a class="header-anchor" href="#_3-risk-tier-auto-elevation" aria-label="Permalink to &quot;3. Risk Tier Auto-Elevation&quot;">​</a></h2><p>Changes to any path in <code>.governance/protected-paths.yml</code> are automatically elevated to the minimum tier listed. A PR touching <code>backend/src/api/v4/</code> is always <code>elevated</code> regardless of how trivial the change appears.</p><p>See <code>.governance/protected-paths.yml</code> for the full list.</p><hr><h2 id="_4-agent-boundaries" tabindex="-1">4. Agent Boundaries <a class="header-anchor" href="#_4-agent-boundaries" aria-label="Permalink to &quot;4. Agent Boundaries&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Authorized areas</th><th>Prohibited</th></tr></thead><tbody><tr><td><code>backend-agent</code></td><td><code>backend/src/</code>, <code>backend/tests/</code>, <code>backend/migrations/</code>, <code>push-proxy/</code></td><td><code>frontend/</code>, <code>.governance/</code>, and protected sub-paths without approval</td></tr><tr><td><code>frontend-agent</code></td><td><code>frontend/src/</code>, <code>frontend/e2e/</code></td><td><code>backend/</code>, <code>.governance/</code></td></tr><tr><td><code>compat-agent</code></td><td>Read: compat surface. Write: <code>docs/superpowers/</code>, <code>previous-analyses/</code></td><td>All production code paths</td></tr></tbody></table><p>For full contract details see <code>.governance/agent-contracts.yml</code> and <code>docs/agent-operating-model.md</code>.</p><hr><h2 id="_5-how-to-update-ownership" tabindex="-1">5. How to Update Ownership <a class="header-anchor" href="#_5-how-to-update-ownership" aria-label="Permalink to &quot;5. How to Update Ownership&quot;">​</a></h2><p>Changing CODEOWNERS is an <code>elevated</code> risk tier change (automatic per <code>protected-paths.yml</code>). It requires:</p><ol><li>Edit <code>.github/CODEOWNERS</code></li><li>Both <code>@senolcolak</code> and <code>@zoorpha</code> must approve the PR</li><li>Verify branch protection is still correct after the change</li></ol><p>CODEOWNERS uses <strong>last-match wins</strong> semantics — the catchall <code>*</code> rule is placed first so specific rules below it take precedence.</p>',26)])])}const u=t(c,[["render",r]]);export{b as __pageData,u as default};
